mapper.select:
SELECT * FROM lawyer_info
ORDER BY created_at DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE lawyer_info
license_number = #{licenseNumber}, firm_name = #{firmName}, specialization = #{specialization}, experience_years = #{experienceYears}, total_consultations = #{totalConsultations}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT u.id AS user_id, u.username, u.avatar, li.firm_name, li.specialization, li.experience_years, li.total_consultations FROM users u INNER JOIN lawyer_info li ON u.id = li.user_id WHERE u.role = 'lawyer' AND u.status = 'active'
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR li.specialization LIKE CONCAT('%', #{keyword}, '%') OR li.firm_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY li.total_consultations DESC, li.experience_years DESC, li.updated_at DESC LIMIT #{offset}, #{limit}
